var fila = new Queue<int>();

// Enqueue — O(1)
fila.Enqueue(10);
fila.Enqueue(20);
fila.Enqueue(30);

// Peek — O(1), não remove
int frente = fila.Peek();  // 10

// Dequeue — O(1)
int removido = fila.Dequeue();  // 10

// Verificar vazio
bool vazia = fila.Count == 0;

codeSnippets.go:
// Go usa channel ou slice como fila
fila := make([]int, 0)

// Enqueue — O(1) amortizado
fila = append(fila, 10)
fila = append(fila, 20)
fila = append(fila, 30)

// Peek — O(1)
frente := fila[0]  // 10

// Dequeue — O(1) com slice reslicing
removido := fila[0]
fila = fila[1:]  // 20, 30

codeSnippets.javascript:
// Array como fila (shift é O(n)); para O(1) use deque customizado
const fila = [];

// Enqueue — O(1)
fila.push(10);
fila.push(20);
fila.push(30);

// Peek — O(1)
const frente = fila[0];  // 10

// Dequeue — O(n) com Array.shift; use LinkedList para O(1)
const removido = fila.shift();  // 10

console.log(fila);  // [20, 30]
